// CreateTransaction handles new transaction requests.
func (s *server) CreateTransaction(ctx context.Context, req *pb.CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	log.Printf("Received CreateTransaction request: %+v", req)

	// Basic validation
	if req.GetAmount() <= 0 {
		return nil, status.Errorf(codes.InvalidArgument, "amount must be positive")
	}
	if req.GetTransactionType() == "TRANSFER" && (req.GetFromAccountId() == "" || req.GetToAccountId() == "") {
		return nil, status.Errorf(codes.InvalidArgument, "from_account_id and to_account_id are required for transfers")
	}
	if req.GetTransactionType() == "DEPOSIT" && req.GetToAccountId() == "" {
		return nil, status.Errorf(codes.InvalidArgument, "to_account_id is required for deposits")
	}
	if req.GetTransactionType() == "WITHDRAWAL" && req.GetFromAccountId() == "" {
		return nil, status.Errorf(codes.InvalidArgument, "from_account_id is required for withdrawals")
	}
	if req.GetFromAccountId() == req.GetToAccountId() && req.GetTransactionType() == "TRANSFER" {
		return nil, status.Errorf(codes.InvalidArgument, "cannot transfer to the same account")
	}

	// Initialize accounts if they don't exist for simplicity in this example
	// In a real system, you'd likely check for account existence first and return an error if not found.
	if req.GetFromAccountId() != "" {
		if _, ok := s.accounts[req.GetFromAccountId()]; !ok {
			s.accounts[req.GetFromAccountId()] = 0.0
		}
	}
	if req.GetToAccountId() != "" {
		if _, ok := s.accounts[req.GetToAccountId()]; !ok {
			s.accounts[req.GetToAccountId()] = 0.0
		}
	}

	// Simulate transaction processing
	switch req.GetTransactionType() {
	case "DEPOSIT":
		s.accounts[req.GetToAccountId()] += req.GetAmount()
	case "WITHDRAWAL":
		if s.accounts[req.GetFromAccountId()] < req.GetAmount() {
			return nil, status.Errorf(codes.FailedPrecondition, "insufficient funds in account %s", req.GetFromAccountId())
		}
		s.accounts[req.GetFromAccountId()] -= req.GetAmount()
	case "TRANSFER":
		if s.accounts[req.GetFromAccountId()] < req.GetAmount() {
			return nil, status.Errorf(codes.FailedPrecondition, "insufficient funds in account %s", req.GetFromAccountId())
		}
		s.accounts[req.GetFromAccountId()] -= req.GetAmount()
		s.accounts[req.GetToAccountId()] += req.GetAmount()
	default:
		return nil, status.Errorf(codes.InvalidArgument, "unsupported transaction type: %s", req.GetTransactionType())
	}

	s.transactionSeq++
	transactionID := fmt.Sprintf("txn-%d", s.transactionSeq)
	now := time.Now().Unix()

	newTransaction := &pb.Transaction{
		Id:              transactionID,
		FromAccountId:   req.GetFromAccountId(),
		ToAccountId:     req.GetToAccountId(),
		Amount:          req.GetAmount(),
		Currency:        req.GetCurrency(),
		TransactionType: req.GetTransactionType(),
		Timestamp:       now,
	}
	s.transactions[transactionID] = newTransaction

	log.Printf("Transaction %s processed successfully. Type: %s, From: %s, To: %s, Amount: %.2f %s. Balances: %v",
		transactionID, req.GetTransactionType(), req.GetFromAccountId(), req.GetToAccountId(), req.GetAmount(), req.GetCurrency(), s.accounts)

	return &pb.CreateTransactionResponse{
		TransactionId: transactionID,
		Success:       true,
		Message:       "Transaction created successfully",
	}, nil
}

